import XCTest
import CryptoKit
@testable import ReticulumSwift

final class TransportInteropTests: XCTestCase {

    // MARK: - Hex Helpers

    private func hex(_ s: String) -> Data {
        var data = Data()
        var index = s.startIndex
        while index < s.endIndex {
            let next = s.index(index, offsetBy: 2)
            data.append(UInt8(s[index..<next], radix: 16)!)
            index = next
        }
        return data
    }

    // ============================================================
    // MARK: - 1. Packet Encoding / Hashing
    // ============================================================

    /// HEADER_1 data packet encodes to exact Python wire bytes.
    func testHeader1PacketEncode() throws {
        let destHash = hex("0102030405060708090a0b0c0d0e0f10")
        let payload = hex("48656c6c6f205265746963756c756d")
        let expectedRaw = hex("00030102030405060708090a0b0c0d0e0f100048656c6c6f205265746963756c756d")

        let header = PacketHeader(
            headerType: .header1,
            hasContext: false,
            transportType: .broadcast,
            destinationType: .single,
            packetType: .data,
            hopCount: 3
        )
        let packet = Packet(header: header, destination: destHash, context: 0x00, data: payload)
        XCTAssertEqual(packet.encode(), expectedRaw, "HEADER_1 encode should match Python")
    }

    /// HEADER_2 data packet encodes to exact Python wire bytes.
    func testHeader2PacketEncode() throws {
        let destHash = hex("0102030405060708090a0b0c0d0e0f10")
        let transportAddr = hex("a1a2a3a4a5a6a7a8a9aaabacadaeafb0")
        let payload = hex("48656c6c6f205265746963756c756d")
        let expectedRaw = hex("5005a1a2a3a4a5a6a7a8a9aaabacadaeafb00102030405060708090a0b0c0d0e0f100048656c6c6f205265746963756c756d")

        let header = PacketHeader(
            headerType: .header2,
            hasContext: false,
            transportType: .transport,
            destinationType: .single,
            packetType: .data,
            hopCount: 5
        )
        let packet = Packet(
            header: header,
            destination: destHash,
            transportAddress: transportAddr,
            context: 0x00,
            data: payload
        )
        XCTAssertEqual(packet.encode(), expectedRaw, "HEADER_2 encode should match Python")
    }

    /// HEADER_1 hashable part matches Python (masked header byte, skip hop count).
    func testHeader1HashablePart() throws {
        let raw = hex("00030102030405060708090a0b0c0d0e0f100048656c6c6f205265746963756c756d")
        let expectedHashable = hex("000102030405060708090a0b0c0d0e0f100048656c6c6f205265746963756c756d")

        let packet = try Packet(from: raw)
