    /// H1 and H2 packets with same dest+context+data produce identical hashes
    /// (transport addr and hop count are excluded from hash computation).
    func testHeader1AndHeader2ProduceSameHash() throws {
        let raw1 = hex("00030102030405060708090a0b0c0d0e0f100048656c6c6f205265746963756c756d")
        let raw2 = hex("5005a1a2a3a4a5a6a7a8a9aaabacadaeafb00102030405060708090a0b0c0d0e0f100048656c6c6f205265746963756c756d")

        let p1 = try Packet(from: raw1)
        let p2 = try Packet(from: raw2)
        XCTAssertEqual(p1.getFullHash(), p2.getFullHash(), "H1 and H2 should produce same packet hash")
    }

