    /// Packet decode→encode round-trip preserves exact bytes.
    func testPacketRoundTrip() throws {
        let origH1 = hex("00030102030405060708090a0b0c0d0e0f100048656c6c6f205265746963756c756d")
        let origH2 = hex("5005a1a2a3a4a5a6a7a8a9aaabacadaeafb00102030405060708090a0b0c0d0e0f100048656c6c6f205265746963756c756d")

        XCTAssertEqual(try Packet(from: origH1).encode(), origH1, "H1 round-trip should preserve bytes")
        XCTAssertEqual(try Packet(from: origH2).encode(), origH2, "H2 round-trip should preserve bytes")
    }

    /// Header flags byte encodes correctly.
    func testHeaderFlagsByte() {
        // HEADER_1, no context, broadcast, single, data, hop=3 → 0x00
        let h1 = PacketHeader(
            headerType: .header1, hasContext: false, transportType: .broadcast,
            destinationType: .single, packetType: .data, hopCount: 3
        )
        XCTAssertEqual(h1.encode(), Data([0x00, 0x03]))

        // HEADER_2, no context, transport, single, data, hop=5 → 0x50
        let h2 = PacketHeader(
            headerType: .header2, hasContext: false, transportType: .transport,
            destinationType: .single, packetType: .data, hopCount: 5
        )
        XCTAssertEqual(h2.encode(), Data([0x50, 0x05]))

        // HEADER_1, no context, broadcast, single, announce, hop=0 → 0x01
        let ann = PacketHeader(
            headerType: .header1, hasContext: false, transportType: .broadcast,
            destinationType: .single, packetType: .announce, hopCount: 0
        )
        XCTAssertEqual(ann.encode(), Data([0x01, 0x00]))

        // HEADER_1, hasContext, broadcast, single, announce, hop=0 → 0x21
        let annCtx = PacketHeader(
            headerType: .header1, hasContext: true, transportType: .broadcast,
            destinationType: .single, packetType: .announce, hopCount: 0
        )
        XCTAssertEqual(annCtx.encode(), Data([0x21, 0x00]))

        // HEADER_1, no context, broadcast, plain, announce, hop=0 → 0x09
        let annPlain = PacketHeader(
            headerType: .header1, hasContext: false, transportType: .broadcast,
            destinationType: .plain, packetType: .announce, hopCount: 0
        )
        XCTAssertEqual(annPlain.encode(), Data([0x09, 0x00]))

        // HEADER_1, broadcast, single, linkRequest, hop=0 → 0x02
        let lr = PacketHeader(
            headerType: .header1, hasContext: false, transportType: .broadcast,
            destinationType: .single, packetType: .linkRequest, hopCount: 0
        )
        XCTAssertEqual(lr.encode(), Data([0x02, 0x00]))
    }

