    func testIdentityHash() throws {
        let encPub = hex("8f40c5adb68f25624ae5b214ea767a6ec94d829d3d7b5e1ad1ba6f3e2138285f")
        let sigPub = hex("29acbae141bccaf0b22e1a94d34d0bc7361e526d0bfe12c89794bc9322966dd7")
        let expectedHash = hex("aca31af0441d81dbec71e82da0b4b5f5")

        let hash = Hashing.identityHash(encryptionPublicKey: encPub, signingPublicKey: sigPub)
        XCTAssertEqual(hash, expectedHash, "Identity hash should match Python")
    }

