    /// Announce payload structure matches Python layout.
    func testAnnouncePayloadStructure() throws {
        let encPriv = hex("000102030405060708090a0b0c0d0e0f101112131415161718191a1b1c1d1e1f")
        let sigPriv = hex("202122232425262728292a2b2c2d2e2f303132333435363738393a3b3c3d3e3f")
        let randomHash = hex("aabbccddee0065e11a80")
        let appData = "TestApp v1.0".data(using: .utf8)!

        let identity = try Identity(encryptionPrivateKeyBytes: encPriv, signingPrivateKeyBytes: sigPriv)
        let dest = Destination(identity: identity, appName: "lxmf", aspects: ["delivery"])
        let announce = Announce(destination: dest, appData: appData, randomHash: randomHash)
        let payload = try announce.build()

        // Verify structure: pubkeys(64) + nameHash(10) + randomHash(10) + signature(64) + appData(12) = 160
        XCTAssertEqual(payload.count, 160, "Announce payload should be 160 bytes")

        // Extract components
        let pubKeys = Data(payload[0..<64])
        let nameHash = Data(payload[64..<74])
        let extractedRandom = Data(payload[74..<84])
        let signature = Data(payload[84..<148])
        let extractedAppData = Data(payload[148...])

        XCTAssertEqual(pubKeys, identity.publicKeys, "Public keys should match")
        XCTAssertEqual(nameHash, dest.nameHash, "Name hash should match")
        XCTAssertEqual(extractedRandom, randomHash, "Random hash should match")
        XCTAssertEqual(signature.count, 64, "Signature should be 64 bytes")
        XCTAssertEqual(extractedAppData, appData, "App data should match")
    }

    /// Python can verify our announce signature (structure matches).
    func testAnnounceSignatureVerifiable() throws {
        let encPriv = hex("000102030405060708090a0b0c0d0e0f101112131415161718191a1b1c1d1e1f")
        let sigPriv = hex("202122232425262728292a2b2c2d2e2f303132333435363738393a3b3c3d3e3f")
        let randomHash = hex("aabbccddee0065e11a80")
        let appData = "TestApp v1.0".data(using: .utf8)!

        let identity = try Identity(encryptionPrivateKeyBytes: encPriv, signingPrivateKeyBytes: sigPriv)
        let dest = Destination(identity: identity, appName: "lxmf", aspects: ["delivery"])

        // Build signed data the same way Python does
        var signedData = Data()
        signedData.append(dest.hash)
        signedData.append(identity.publicKeys)
        signedData.append(dest.nameHash)
        signedData.append(randomHash)
        signedData.append(appData)

        XCTAssertEqual(signedData, hex("fae321c442e3c9bdcd7a3e79d850e03c8f40c5adb68f25624ae5b214ea767a6ec94d829d3d7b5e1ad1ba6f3e2138285f29acbae141bccaf0b22e1a94d34d0bc7361e526d0bfe12c89794bc9322966dd76ec60bc318e2c0f0d908aabbccddee0065e11a80546573744170702076312e30"),
                       "Signed data should match Python byte-for-byte")

        // Sign and verify
        let announce = Announce(destination: dest, appData: appData, randomHash: randomHash)
        let payload = try announce.build()
        let signature = Data(payload[84..<148])

        // Verify our own signature
        XCTAssertTrue(identity.verify(signature: signature, for: signedData),
                      "Swift signature should be verifiable with identity public key")
    }

    /// Python-generated announce signature is verifiable by Swift.
    func testVerifyPythonAnnounceSignature() throws {
        let sigPub = hex("29acbae141bccaf0b22e1a94d34d0bc7361e526d0bfe12c89794bc9322966dd7")
        let signedData = hex("fae321c442e3c9bdcd7a3e79d850e03c8f40c5adb68f25624ae5b214ea767a6ec94d829d3d7b5e1ad1ba6f3e2138285f29acbae141bccaf0b22e1a94d34d0bc7361e526d0bfe12c89794bc9322966dd76ec60bc318e2c0f0d908aabbccddee0065e11a80546573744170702076312e30")
        let pythonSig = hex("a3d4545e587f95175a4b7096b12913406848fb575a6a0ae034b0db14b4bcf6f8f0c981e7f77c4458d75b1ca59b944bb3655822672c92db0bcfdf2dbd0a70f605")

        let valid = try Identity.verify(signature: pythonSig, for: signedData, publicKey: sigPub)
        XCTAssertTrue(valid, "Python announce signature should verify in Swift")
    }

    /// Announce with ratchet: signature from Python is verifiable.
    func testVerifyPythonRatchetAnnounceSignature() throws {
        let sigPub = hex("29acbae141bccaf0b22e1a94d34d0bc7361e526d0bfe12c89794bc9322966dd7")
        let signedData = hex("fae321c442e3c9bdcd7a3e79d850e03c8f40c5adb68f25624ae5b214ea767a6ec94d829d3d7b5e1ad1ba6f3e2138285f29acbae141bccaf0b22e1a94d34d0bc7361e526d0bfe12c89794bc9322966dd76ec60bc318e2c0f0d908aabbccddee0065e11a80404142434445464748494a4b4c4d4e4f505152535455565758595a5b5c5d5e5f546573744170702076312e30")
        let pythonSig = hex("8d09de7d8b231e7970fa85f086060f9fc4e4437ecc6cef90e7ba76feb3f32d2acca8dd83aa2ad50841917ded9f6afa7db58b99c5176bc324a084479a38dee409")

        let valid = try Identity.verify(signature: pythonSig, for: signedData, publicKey: sigPub)
        XCTAssertTrue(valid, "Python ratchet announce signature should verify in Swift")
