    /// Announce with ratchet includes ratchet key in payload and sets hasContext.
    func testAnnounceWithRatchetFormat() throws {
        let encPriv = hex("000102030405060708090a0b0c0d0e0f101112131415161718191a1b1c1d1e1f")
        let sigPriv = hex("202122232425262728292a2b2c2d2e2f303132333435363738393a3b3c3d3e3f")
        let randomHash = hex("aabbccddee0065e11a80")
        let ratchetKey = hex("404142434445464748494a4b4c4d4e4f505152535455565758595a5b5c5d5e5f")
        let appData = "TestApp v1.0".data(using: .utf8)!

        let identity = try Identity(encryptionPrivateKeyBytes: encPriv, signingPrivateKeyBytes: sigPriv)
        let dest = Destination(identity: identity, appName: "lxmf", aspects: ["delivery"])
        let announce = Announce(
            destination: dest, appData: appData, randomHash: randomHash, ratchet: ratchetKey
        )

        // Payload should be: pubkeys(64) + nameHash(10) + randomHash(10) + ratchet(32) + sig(64) + appData(12) = 192
        let payload = try announce.build()
        XCTAssertEqual(payload.count, 192, "Ratchet announce payload should be 192 bytes")

        // Ratchet key at offset 84
        let extractedRatchet = Data(payload[84..<116])
        XCTAssertEqual(extractedRatchet, ratchetKey, "Ratchet key should be at correct offset")

        // Packet should have hasContext=true
        let packet = try announce.buildPacket()
        XCTAssertTrue(packet.header.hasContext, "Ratchet announce should set hasContext")
        XCTAssertEqual(packet.header.encode()[0], 0x21, "Flags byte should be 0x21 with context")
    }

