    /// Random hash timestamp encoding matches Python: bytes[5:10] = big-endian Unix timestamp.
    func testRandomHashTimestamp() {
        let randomHash = hex("aabbccddee0065e11a80")

        // Extract timestamp from bytes [5:10]
        let tsBytes = Data(randomHash[5..<10])
        var ts: UInt64 = 0
        for b in tsBytes {
            ts = (ts << 8) | UInt64(b)
        }
        XCTAssertEqual(ts, 1709251200, "Extracted timestamp should match")
    }

