    /// Link ID from LINKREQUEST matches Python computation.
    func testLinkIdComputation() throws {
        let ephEncPriv = hex("6465666768696a6b6c6d6e6f707172737475767778797a7b7c7d7e7f80818283")
        let ephSigPriv = hex("8485868788898a8b8c8d8e8f909192939495969798999a9b9c9d9e9fa0a1a2a3")
        let expectedLinkId = hex("e8808769e59cf2f4c1805801cdf64985")

        // Create identity and destination for the link request
        let encPriv = hex("000102030405060708090a0b0c0d0e0f101112131415161718191a1b1c1d1e1f")
        let sigPriv = hex("202122232425262728292a2b2c2d2e2f303132333435363738393a3b3c3d3e3f")
        let identity = try Identity(encryptionPrivateKeyBytes: encPriv, signingPrivateKeyBytes: sigPriv)
        let dest = Destination(identity: identity, appName: "lxmf", aspects: ["delivery"])

        // Create link request with known ephemeral keys
        let ephEncKey = try Curve25519.KeyAgreement.PrivateKey(rawRepresentation: ephEncPriv)
        let ephSigKey = try Curve25519.Signing.PrivateKey(rawRepresentation: ephSigPriv)

        let lr = LinkRequest(
            destination: dest,
            ephemeralEncryptionPrivateKey: ephEncKey,
            ephemeralSigningPrivateKey: ephSigKey,
            signaling: Data([0x20, 0x01, 0xF4])  // default MTU 500
        )

        // Verify public keys match Python derivation
        XCTAssertEqual(
            Data(lr.ephemeralEncryptionPublicKey.rawRepresentation),
            hex("7d9c24316539825c1896e57f28197746793ce60cbee3ad47da9d07b85fa55e2a"),
            "Ephemeral enc pub should match Python"
        )
        XCTAssertEqual(
            Data(lr.ephemeralSigningPublicKey.rawRepresentation),
            hex("8befe61c3095da4d71f14befe220ff9a76e0c5b5d046204ee3d70761aae839fc"),
            "Ephemeral sig pub should match Python"
        )

        // Request data should be 67 bytes
        XCTAssertEqual(lr.requestData.count, 67, "LR data should be 67 bytes")

        // Link ID should match Python
        XCTAssertEqual(lr.linkId, expectedLinkId, "Link ID should match Python")
    }

    /// LINKREQUEST packet raw bytes match Python.
    func testLinkRequestRawBytes() throws {
        let ephEncPriv = hex("6465666768696a6b6c6d6e6f707172737475767778797a7b7c7d7e7f80818283")
        let ephSigPriv = hex("8485868788898a8b8c8d8e8f909192939495969798999a9b9c9d9e9fa0a1a2a3")
        let expectedRaw = hex("0200fae321c442e3c9bdcd7a3e79d850e03c007d9c24316539825c1896e57f28197746793ce60cbee3ad47da9d07b85fa55e2a8befe61c3095da4d71f14befe220ff9a76e0c5b5d046204ee3d70761aae839fc2001f4")

        let encPriv = hex("000102030405060708090a0b0c0d0e0f101112131415161718191a1b1c1d1e1f")
        let sigPriv = hex("202122232425262728292a2b2c2d2e2f303132333435363738393a3b3c3d3e3f")
        let identity = try Identity(encryptionPrivateKeyBytes: encPriv, signingPrivateKeyBytes: sigPriv)
