    /// Token encrypt with known IV matches Python byte-for-byte.
    func testTokenEncryptMatchesPython() throws {
        let derivedKey = hex("7a685fafdd211c9a6e78d39cb0b4403b547bd47fcef8258b1cd12a46b06f0c790943ee578263da63e31f70c9cdebf9add3508104dac945924a5a5ff04db6f108")
        let iv = hex("000102030405060708090a0b0c0d0e0f")
        let plaintext = "Hello, Reticulum!".data(using: .utf8)!
        let expected = hex("000102030405060708090a0b0c0d0e0f583f2eae96cbf7360d05f71a4b405e95de9aa84a9f7eb0f5fd3676032ec972b7c56ddb6a93bea779c44ac925f6e77aac5eaf04d307dabe946d697263d0b26a8b")

        let token = try Token(derivedKey: derivedKey)
        let encrypted = try token.encrypt(plaintext, iv: iv)
        XCTAssertEqual(encrypted, expected, "Token encrypt should match Python byte-for-byte")
    }

    /// Token decrypt of Python-encrypted data produces correct plaintext.
    func testTokenDecryptPythonData() throws {
        let derivedKey = hex("7a685fafdd211c9a6e78d39cb0b4403b547bd47fcef8258b1cd12a46b06f0c790943ee578263da63e31f70c9cdebf9add3508104dac945924a5a5ff04db6f108")
        let encrypted = hex("000102030405060708090a0b0c0d0e0f583f2eae96cbf7360d05f71a4b405e95de9aa84a9f7eb0f5fd3676032ec972b7c56ddb6a93bea779c44ac925f6e77aac5eaf04d307dabe946d697263d0b26a8b")
        let expectedPlaintext = "Hello, Reticulum!".data(using: .utf8)!

        let token = try Token(derivedKey: derivedKey)
        let decrypted = try token.decrypt(encrypted)
        XCTAssertEqual(decrypted, expectedPlaintext, "Token decrypt should produce correct plaintext")
    }

    /// Token encrypt→decrypt round-trip.
    func testTokenRoundTrip() throws {
        let derivedKey = hex("7a685fafdd211c9a6e78d39cb0b4403b547bd47fcef8258b1cd12a46b06f0c790943ee578263da63e31f70c9cdebf9add3508104dac945924a5a5ff04db6f108")
        let plaintext = "Hello, Reticulum!".data(using: .utf8)!

        let token = try Token(derivedKey: derivedKey)
