    /// Token with tampered HMAC is rejected.
    func testTokenTamperedHmacRejected() throws {
        let derivedKey = hex("7a685fafdd211c9a6e78d39cb0b4403b547bd47fcef8258b1cd12a46b06f0c790943ee578263da63e31f70c9cdebf9add3508104dac945924a5a5ff04db6f108")
        var encrypted = hex("000102030405060708090a0b0c0d0e0f583f2eae96cbf7360d05f71a4b405e95de9aa84a9f7eb0f5fd3676032ec972b7c56ddb6a93bea779c44ac925f6e77aac5eaf04d307dabe946d697263d0b26a8b")

        // Tamper with last byte of HMAC
        encrypted[encrypted.count - 1] ^= 0xFF

        let token = try Token(derivedKey: derivedKey)
        XCTAssertThrowsError(try token.decrypt(encrypted), "Tampered HMAC should be rejected")
    }

