    // ============================================================
    // MARK: - 8. Announce Timing
    // ============================================================

    /// Random hash timestamp embedding: bytes[5:10] big-endian Unix time.
    func testRandomHashTimestampEncoding() {
        let timestamp: UInt64 = 1709251200
        var bytes = [UInt8](repeating: 0, count: 10)

        // Random part (first 5 bytes)
        bytes[0] = 0xaa; bytes[1] = 0xbb; bytes[2] = 0xcc; bytes[3] = 0xdd; bytes[4] = 0xee

        // Timestamp (last 5 bytes, big-endian)
        bytes[5] = UInt8((timestamp >> 32) & 0xFF)
        bytes[6] = UInt8((timestamp >> 24) & 0xFF)
        bytes[7] = UInt8((timestamp >> 16) & 0xFF)
        bytes[8] = UInt8((timestamp >> 8) & 0xFF)
        bytes[9] = UInt8(timestamp & 0xFF)

        let expected = hex("aabbccddee0065e11a80")
        XCTAssertEqual(Data(bytes), expected, "Random hash with embedded timestamp should match Python")
    }

    /// Timestamp extraction from random hash matches Python.
    func testRandomHashTimestampExtraction() {
        let randomHash = hex("aabbccddee0065e11a80")

        // Extract 5-byte big-endian timestamp from bytes [5:10]
        var ts: UInt64 = 0
        for i in 5..<10 {
            ts = (ts << 8) | UInt64(randomHash[i])
        }
        XCTAssertEqual(ts, 1709251200, "Extracted timestamp should be 1709251200")
    }

    /// PATHFINDER_G delay is the base delay before first retransmission.
    func testPathfinderGraceDelay() {
        // Python: retransmit_timeout = now + PATHFINDER_G + random(0, PATHFINDER_RW)
        // So minimum delay = PATHFINDER_G = 5.0s, maximum = PATHFINDER_G + PATHFINDER_RW = 5.5s
        let minDelay = TransportConstants.PATHFINDER_G
        let maxDelay = TransportConstants.PATHFINDER_G + TransportConstants.PATHFINDER_RW
        XCTAssertEqual(minDelay, 5.0, "Minimum retransmit delay should be 5.0s")
        XCTAssertEqual(maxDelay, 5.5, "Maximum retransmit delay should be 5.5s")
    }

