    /// Passthrough contexts (NOT link-encrypted) match Python Packet.pack().
    func testPassthroughContexts() {
        // Python Packet.pack() treats these as passthrough (no link encryption):
        // - KEEPALIVE (0xFA): sent as raw 0xFF/0xFE marker
        // - LRPROOF (0xFF): link establishment proof
        // - RESOURCE (0x01): Resource class handles its own encryption
        let passthroughContexts: [UInt8] = [
            PacketContext.KEEPALIVE,
            PacketContext.LRPROOF,
            PacketContext.RESOURCE,
        ]

        XCTAssertTrue(passthroughContexts.contains(0xFA))
        XCTAssertTrue(passthroughContexts.contains(0xFF))
        XCTAssertTrue(passthroughContexts.contains(0x01))
    }

    /// Encrypted contexts (link-encrypted) match Python Packet.pack().
    func testEncryptedContexts() {
        // These contexts are link-encrypted in Python Packet.pack():
        // - DATA/NONE (0x00): Normal data
        // - LINKIDENTIFY (0xFB): Identity proof
        // - LINKCLOSE (0xFC): Graceful close
        // - LRRTT (0xFE): RTT measurement
        let encryptedContexts: [UInt8] = [
            PacketContext.NONE,
            PacketContext.LINKIDENTIFY,
            PacketContext.LINKCLOSE,
            PacketContext.LRRTT,
        ]

        XCTAssertTrue(encryptedContexts.contains(0x00))
        XCTAssertTrue(encryptedContexts.contains(0xFB))
        XCTAssertTrue(encryptedContexts.contains(0xFC))
        XCTAssertTrue(encryptedContexts.contains(0xFE))
    }

