    /// Header bit positions match Python Packet.py.
    func testHeaderBitPositions() {
        // IFAC flag = bit 7 = 0x80
        var h = PacketHeader(headerType: .header1, hasContext: false, hasIFAC: true,
                             transportType: .broadcast, destinationType: .single, packetType: .data, hopCount: 0)
        XCTAssertEqual(h.encode()[0] & 0x80, 0x80, "IFAC flag should be bit 7")

        // Header type = bit 6 = 0x40
        h = PacketHeader(headerType: .header2, hasContext: false,
                         transportType: .broadcast, destinationType: .single, packetType: .data, hopCount: 0)
        XCTAssertEqual(h.encode()[0] & 0x40, 0x40, "Header type should be bit 6")

        // Context flag = bit 5 = 0x20
        h = PacketHeader(headerType: .header1, hasContext: true,
                         transportType: .broadcast, destinationType: .single, packetType: .data, hopCount: 0)
        XCTAssertEqual(h.encode()[0] & 0x20, 0x20, "Context flag should be bit 5")

        // Transport type = bit 4 = 0x10
        h = PacketHeader(headerType: .header1, hasContext: false,
                         transportType: .transport, destinationType: .single, packetType: .data, hopCount: 0)
        XCTAssertEqual(h.encode()[0] & 0x10, 0x10, "Transport type should be bit 4")

        // Destination type = bits 3-2
        h = PacketHeader(headerType: .header1, hasContext: false,
                         transportType: .broadcast, destinationType: .plain, packetType: .data, hopCount: 0)
        XCTAssertEqual(h.encode()[0] & 0x0C, 0x08, "Plain dest type should be 0b10 in bits 3-2")

        h = PacketHeader(headerType: .header1, hasContext: false,
                         transportType: .broadcast, destinationType: .link, packetType: .data, hopCount: 0)
        XCTAssertEqual(h.encode()[0] & 0x0C, 0x0C, "Link dest type should be 0b11 in bits 3-2")

        // Packet type = bits 1-0
        h = PacketHeader(headerType: .header1, hasContext: false,
                         transportType: .broadcast, destinationType: .single, packetType: .proof, hopCount: 0)
        XCTAssertEqual(h.encode()[0] & 0x03, 0x03, "Proof packet type should be 0b11 in bits 1-0")
    }

    /// Link keep-alive magic bytes match Python.
    func testKeepaliveMagicBytes() {
        XCTAssertEqual(LinkConstants.KEEPALIVE_INITIATOR, 0xFF, "Initiator keepalive should be 0xFF")
        XCTAssertEqual(LinkConstants.KEEPALIVE_RESPONDER, 0xFE, "Responder keepalive should be 0xFE")
    }

    /// MDU formula: floor((mtu - 1 - 19 - 48) / 16) * 16 - 1
    func testMduFormula() {
        // Python: MDU = floor((MTU - IFAC_MIN_SIZE - HEADER_MINSIZE - TOKEN_OVERHEAD) / AES128_BLOCKSIZE) * AES128_BLOCKSIZE - 1
        // IFAC_MIN_SIZE=1, HEADER_MINSIZE=19 (2 header + 16 dest + 1 context), TOKEN_OVERHEAD=48, AES_BLOCKSIZE=16
        func mdu(for hwMtu: Int) -> Int {
            return ((hwMtu - 1 - 19 - 48) / 16) * 16 - 1
        }

        XCTAssertEqual(mdu(for: 500), 431, "MDU for MTU=500 should be 431")
        XCTAssertEqual(mdu(for: 262144), 262_063, "MDU for TCP MTU should be 262063")
        XCTAssertEqual(mdu(for: 1196), 1_119, "MDU for Auto MTU should be 1119")
        XCTAssertEqual(mdu(for: 508), 431, "MDU for BLE MTU should be 431")

        // Verify LINK_MDU constant matches the formula for default MTU
        XCTAssertEqual(LinkConstants.LINK_MDU, mdu(for: 500), "LINK_MDU should match formula for MTU=500")
    }
